using Autodesk.AutoCAD.DatabaseServices;using Autodesk.AutoCAD.Geometry;using System;using System.Collections.Generic;using System.Linq;
namespace Tgirrr.CadLisp { internal static class DripLayoutService {internal static Vector2d Direction(Polyline p){double best=-1;Vector2d dir=Vector2d.XAxis;for(int i=0;i<p.NumberOfVertices;i++){if(p.GetSegmentType(i)!=SegmentType.Line)continue;var seg=p.GetLineSegment2dAt(i);if(seg.Length>best){best=seg.Length;dir=seg.Direction;}}return dir.GetNormal();}internal static DBObjectCollection Inner(Polyline p,double inset){if(inset==0){var c=new DBObjectCollection();c.Add(p.Clone() as Polyline);return c;}DBObjectCollection a=null,b=null;try{a=p.GetOffsetCurves(inset);}catch{}try{b=p.GetOffsetCurves(-inset);}catch{}var candidates=new List<Polyline>();if(a!=null)candidates.AddRange(a.Cast<DBObject>().OfType<Polyline>());if(b!=null)candidates.AddRange(b.Cast<DBObject>().OfType<Polyline>());double sourceArea=Math.Abs(p.Area);double tolerance=Math.Max(sourceArea*1e-9,1e-9);var inside=candidates.Where(x=>{try{return x.Closed&&Math.Abs(x.Area)<sourceArea-tolerance;}catch{return false;}}).OrderByDescending(x=>Math.Abs(x.Area)).ToList();var result=new DBObjectCollection();foreach(var x in inside)result.Add(x);foreach(var x in candidates.Except(inside))x.Dispose();return result;}internal static bool PointInside(Polyline p,Point2d point){var far=new LineSegment2d(point,new Point2d(p.GeometricExtents.MaxPoint.X+(p.GeometricExtents.MaxPoint-p.GeometricExtents.MinPoint).Length+1,point.Y+0.1234567));int hits=0;for(int i=0;i<p.NumberOfVertices;i++){if(p.GetSegmentType(i)==SegmentType.Line){var pts=p.GetLineSegment2dAt(i).IntersectWith(far);hits+=pts?.Length??0;}else if(p.GetSegmentType(i)==SegmentType.Arc){var pts=p.GetArcSegment2dAt(i).IntersectWith(far);hits+=pts?.Length??0;}}return hits%2==1;}internal static List<Polyline> CurvedFill(Polyline boundary,double spacing){var result=new List<Polyline>();var seed=LongestArcChain(boundary);if(seed==null)return result;int misses=0;for(int signIndex=0;signIndex<2&&result.Count==0;signIndex++){double sign=signIndex==0?1:-1;misses=0;for(int n=1;n<10000&&misses<3;n++){DBObjectCollection offsets;try{offsets=seed.GetOffsetCurves(sign*n*spacing);}catch{break;}bool valid=false;foreach(Polyline curve in offsets.Cast<DBObject>().OfType<Polyline>()){var fitted=ExtendToBoundary(curve,boundary);curve.Dispose();if(fitted!=null){result.Add(fitted);valid=true;}}misses=valid?0:misses+1;}}seed.Dispose();return result;}internal sealed class ArcRun{internal readonly List<int> Segments=new List<int>();internal double Length,WeightedRadius,Turn,RadiusVariation;internal double Score=>Length*(1.0+Math.Min(WeightedRadius/Math.Max(Length,1e-9),3.0))/(1.0+RadiusVariation*2.0+Math.Max(0,Turn-Math.PI*0.85)*2.0);}
internal static Polyline LongestArcChain(Polyline boundary){int count=boundary.NumberOfVertices;var runs=new List<ArcRun>();for(int seed=0;seed<count;seed++){if(boundary.GetSegmentType(seed)!=SegmentType.Arc)continue;var run=new ArcRun();double firstRadius=0,lastRadius=0,lastSign=0;for(int k=0;k<count;k++){int i=(seed+k)%count;if(boundary.GetSegmentType(i)!=SegmentType.Arc)break;var arc=boundary.GetArcSegment2dAt(i);double bulge=boundary.GetBulgeAt(i),sign=Math.Sign(bulge),radius=arc.Radius,turn=Math.Abs(arc.EndAngle-arc.StartAngle);if(turn>Math.PI*2)turn=Math.PI*2-turn;if(run.Segments.Count>0){double ratio=Math.Max(radius,lastRadius)/Math.Max(Math.Min(radius,lastRadius),1e-9);if(sign!=lastSign||ratio>1.8||run.Turn+turn>Math.PI*1.15)break;run.RadiusVariation+=Math.Abs(radius-lastRadius)/Math.Max(lastRadius,1e-9);}else firstRadius=radius;double length=radius*turn;run.Segments.Add(i);run.Length+=length;run.WeightedRadius+=radius*length;run.Turn+=turn;lastRadius=radius;lastSign=sign;}if(run.Segments.Count>0){run.WeightedRadius/=Math.Max(run.Length,1e-9);runs.Add(run);seed+=run.Segments.Count-1;}}var best=runs.OrderByDescending(r=>r.Score).FirstOrDefault();if(best==null)return null;var poly=new Polyline(best.Segments.Count+1);for(int k=0;k<best.Segments.Count;k++){int i=best.Segments[k];poly.AddVertexAt(k,boundary.GetPoint2dAt(i),boundary.GetBulgeAt(i),0,0);}int last=(best.Segments[best.Segments.Count-1]+1)%count;poly.AddVertexAt(best.Segments.Count,boundary.GetPoint2dAt(last),0,0,0);return poly;}internal static Polyline ExtendToBoundary(Polyline curve,Polyline boundary){if(curve.NumberOfVertices<2)return null;double reach=(boundary.GeometricExtents.MaxPoint-boundary.GeometricExtents.MinPoint).Length*2;var start=curve.StartPoint;var end=curve.EndPoint;Vector3d startTan,endTan;try{startTan=curve.GetFirstDerivative(start).GetNormal();endTan=curve.GetFirstDerivative(end).GetNormal();}catch{return null;}var startProbe=new Line(start-startTan*reach,start+startTan*reach);var endProbe=new Line(end-endTan*reach,end+endTan*reach);var sPoints=new Point3dCollection();var ePoints=new Point3dCollection();boundary.IntersectWith(startProbe,Intersect.OnBothOperands,sPoints,IntPtr.Zero,IntPtr.Zero);boundary.IntersectWith(endProbe,Intersect.OnBothOperands,ePoints,IntPtr.Zero,IntPtr.Zero);startProbe.Dispose();endProbe.Dispose();var startCandidates=sPoints.Cast<Point3d>().Where(p=>p.DistanceTo(start)>1e-7).OrderBy(p=>(p-start).DotProduct(startTan)).ToList();var endCandidates=ePoints.Cast<Point3d>().Where(p=>p.DistanceTo(end)>1e-7).OrderByDescending(p=>(p-end).DotProduct(endTan)).ToList();if(startCandidates.Count==0||endCandidates.Count==0)return null;var newStart=startCandidates[0];var newEnd=endCandidates[0];var output=(Polyline)curve.Clone();output.SetPointAt(0,newStart.Convert2d(new Plane()));output.SetPointAt(output.NumberOfVertices-1,newEnd.Convert2d(new Plane()));Point3d mid;try{mid=output.GetPointAtDist(output.Length/2);}catch{output.Dispose();return null;}if(!PointInside(boundary,new Point2d(mid.X,mid.Y))){output.Dispose();return null;}return output;}internal static List<Line> Fill(Polyline boundary,double spacing,Vector2d direction){if(Enumerable.Range(0,boundary.NumberOfVertices).All(i=>boundary.GetSegmentType(i)==SegmentType.Line)){var polygon=Enumerable.Range(0,boundary.NumberOfVertices).Select(i=>{var p=boundary.GetPoint2dAt(i);return new DripPoint(p.X,p.Y);}).ToList();return DripFillGeometry.Fill(polygon,spacing,new DripVector(direction.X,direction.Y)).Select(s=>new Line(new Point3d(s.Start.X,s.Start.Y,boundary.Elevation),new Point3d(s.End.X,s.End.Y,boundary.Elevation))).ToList();}var normal=direction.GetPerpendicularVector();var ext=boundary.GeometricExtents;var corners=new[]{new Point2d(ext.MinPoint.X,ext.MinPoint.Y),new Point2d(ext.MinPoint.X,ext.MaxPoint.Y),new Point2d(ext.MaxPoint.X,ext.MinPoint.Y),new Point2d(ext.MaxPoint.X,ext.MaxPoint.Y)};double min=corners.Min(p=>p.GetAsVector().DotProduct(normal)),max=corners.Max(p=>p.GetAsVector().DotProduct(normal)),reach=(ext.MaxPoint-ext.MinPoint).Length*2+spacing;var result=new List<Line>();for(double d=Math.Ceiling(min/spacing)*spacing;d<=max;d+=spacing){var center=new Point2d(normal.X*d,normal.Y*d);var a=center-direction*reach;var b=center+direction*reach;var probe=new Line(new Point3d(a.X,a.Y,boundary.Elevation),new Point3d(b.X,b.Y,boundary.Elevation));var points=new Point3dCollection();boundary.IntersectWith(probe,Intersect.OnBothOperands,points,IntPtr.Zero,IntPtr.Zero);probe.Dispose();var ordered=points.Cast<Point3d>().OrderBy(p=>p.GetAsVector().DotProduct(new Vector3d(direction.X,direction.Y,0))).ToList();var unique=new List<Point3d>();double pointTolerance=Math.Max(reach*1e-9,1e-7);foreach(var point in ordered)if(unique.Count==0||point.DistanceTo(unique[unique.Count-1])>pointTolerance)unique.Add(point);for(int i=0;i+1<unique.Count;i+=2)if(unique[i].DistanceTo(unique[i+1])>pointTolerance)result.Add(new Line(unique[i],unique[i+1]));}return result;}}
}
